+/**
+ * Webhook notification adapter.
+ *
+ * Implements NotificationAdapter for the webhook channel with:
+ * - URL validation
+ * - JSON payload formatting
+ * - Pluggable transport (inject any HTTP POST function)
+ * - In-memory fallback transport for development/testing
+ */
+
+import type { NotificationAdapter } from './notification.adapter.js';
+import type {
+  NotificationChannel,
+  NotificationPayload,
+  NotificationResult,
+} from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+/** Structure representing a formatted webhook request ready for delivery. */
+export interface WebhookRequest {
+  url: string;
+  headers: Record<string, string>;
+  body: string;
+}
+
+/** Transport function signature — adapts to any HTTP client. */
+export type WebhookTransport = (request: WebhookRequest) => Promise<{ requestId: string }>;
+
+/** Record of a sent webhook, stored in-memory for inspection. */
+export interface SentWebhookRecord {
+  payload: NotificationPayload;
+  request: WebhookRequest;
+  requestId: string;
+  timestamp: Date;
+}
+
+/** Configuration for the webhook adapter. */
+export interface WebhookAdapterConfig {
+  /** The URL to POST webhook notifications to. */
+  url: string;
+  /** Optional secret for signing payloads. */
+  secret?: string;
+  /** Optional custom transport. Falls back to in-memory transport if omitted. */
+  transport?: WebhookTransport;
+}
+
+/** Validate that a string is a plausible HTTP(S) URL. */
+function isValidWebhookUrl(url: string): boolean {
+  if (!url) return false;
+  return /^https?:\/\/.+/.test(url);
+}
+
+/** Format a notification payload as a JSON webhook body. */
+function formatWebhookBody(payload: NotificationPayload): string {
+  return JSON.stringify({
+    event: payload.type,
+    recipient: payload.recipient,
+    subject: payload.subject,
+    body: payload.body,
+    metadata: payload.metadata ?? {},
+    timestamp: new Date().toISOString(),
+  });
+}
+
+/** Default in-memory transport for development and testing. */
+function createInMemoryTransport(): WebhookTransport {
+  let counter = 0;
+  return async () => ({ requestId: `wh-${Date.now()}-${++counter}` });
+}
+
+export class WebhookNotificationAdapter implements NotificationAdapter {
+  readonly channel: NotificationChannel = 'webhook';
+  private logger = new Logger('WebhookAdapter');
+  private sent: SentWebhookRecord[] = [];
+  private transport: WebhookTransport;
+  private url: string;
+  private secret?: string;
+
+  constructor(config?: Partial<WebhookAdapterConfig>) {
+    this.url = config?.url ?? '';
+    this.secret = config?.secret;
+    this.transport = config?.transport ?? createInMemoryTransport();
+  }
+
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    if (!isValidWebhookUrl(this.url)) {
+      this.logger.warn(`Invalid webhook URL: ${this.url}`);
+      return {
+        success: false,
+        channel: this.channel,
+        recipient: payload.recipient,
+        error: `Invalid webhook URL: ${this.url}`,
+      };
+    }
+
+    const body = formatWebhookBody(payload);
+    const headers: Record<string, string> = {
+      'Content-Type': 'application/json',
+    };
+
+    if (this.secret) {
+      headers['X-Webhook-Secret'] = this.secret;
+    }
+
+    const request: WebhookRequest = {
+      url: this.url,
+      headers,
+      body,
+    };
+
+    try {
+      const { requestId } = await this.transport(request);
+
+      this.logger.info(`Webhook sent to ${this.url} for ${payload.recipient} [${requestId}]`);
+      this.sent.push({ payload, request, requestId, timestamp: new Date() });
+
+      return {
+        success: true,
+        channel: this.channel,
+        recipient: payload.recipient,
+        messageId: requestId,
+      };
+    } catch (err) {
+      const errorMessage = err instanceof Error ? err.message : String(err);
+      this.logger.error(`Failed to send webhook to ${this.url}: ${errorMessage}`);
+
+      return {
+        success: false,
+        channel: this.channel,
+        recipient: payload.recipient,
+        error: errorMessage,
+      };
+    }
+  }
