      const noSecret = new WebhookNotificationAdapter({
        url: 'https://hooks.example.com/notify',
        transport,
      });
      await noSecret.send(makePayload());
      expect(captured[0]!.headers['X-Webhook-Secret']).toBeUndefined();
    });
  });

  describe('send success', () => {
    it('should return success result with requestId as messageId', async () => {
      const result = await adapter.send(makePayload());
      expect(result.success).toBe(true);
      expect(result.channel).toBe('webhook');
      expect(result.recipient).toBe('alice@example.com');
      expect(result.messageId).toBeDefined();
    });

    it('should track sent webhooks', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: 'bob@example.com' }));
      const sent = adapter.getSentWebhooks();
      expect(sent).toHaveLength(2);
      expect(sent[0]!.payload.recipient).toBe('alice@example.com');
      expect(sent[1]!.payload.recipient).toBe('bob@example.com');
    });

    it('should store request in sent records', async () => {
      await adapter.send(makePayload());
      const sent = adapter.getSentWebhooks();
      expect(sent[0]!.request.url).toBe('https://hooks.example.com/notify');
      expect(sent[0]!.request.headers['Content-Type']).toBe('application/json');
    });
  });

  describe('transport failure', () => {
    it('should return failure result when transport throws', async () => {
      const failing: WebhookTransport = async () => {
        throw new Error('Connection refused');
      };
      const failAdapter = new WebhookNotificationAdapter({
        url: 'https://hooks.example.com/notify',
        transport: failing,
      });
      const result = await failAdapter.send(makePayload());
      expect(result.success).toBe(false);
      expect(result.error).toBe('Connection refused');
      expect(result.channel).toBe('webhook');
    });

    it('should not record failed sends in sent list', async () => {
      const failing: WebhookTransport = async () => {
        throw new Error('timeout');
      };
      const failAdapter = new WebhookNotificationAdapter({
        url: 'https://hooks.example.com/notify',
        transport: failing,
      });
      await failAdapter.send(makePayload());
      expect(failAdapter.getSentWebhooks()).toHaveLength(0);
    });
  });

  describe('clearSentWebhooks', () => {
    it('should clear sent records', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentWebhooks()).toHaveLength(1);
      adapter.clearSentWebhooks();
      expect(adapter.getSentWebhooks()).toHaveLength(0);
    });
  });
});

